from datasets import load_from_disk
import numpy as np
import pandas as pd
from scipy.optimize import minimize, differential_evolution

ds = load_from_disk('/app/data')
df = pd.DataFrame(ds[:])

N = df['non_vocab_parameters'].values
V = df['vocab_size'].values
D = df['num_characters'].values
L = df['unigram_normalized_loss'].values

# Better approach: fit using huber-ish loss in log of log-distance from limit
# Use the Chinchilla functional form: L = E + A/N^α + B/D^β
# but try with V via N_total = N_nv + V*d
# Actually let me explore a wider set of forms more systematically

forms = {}

# F1: L = c + A/N^a + B/V^b + C/D^g
def F1(p):
    c, A, a, B, b, C, g = p
    return np.mean((c + A*N**(-a) + B*V**(-b) + C*D**(-g) - L)**2)
forms['F1'] = (F1, 7)

# F2: L = c + A/N^a * V^p + C/D^g (params and vocab interact)
def F2(p):
    c, A, a, p_, C, g = p
    return np.mean((c + A*N**(-a)*V**p_ + C*D**(-g) - L)**2)
forms['F2'] = (F2, 6)

# F3: L = c + A/N^a + C/D^g * V^p
def F3(p):
    c, A, a, C, g, p_ = p
    return np.mean((c + A*N**(-a) + C*D**(-g)*V**p_ - L)**2)
forms['F3'] = (F3, 6)

# F4: L = c + A/N^a * V^p + C/D^g * V^q
def F4(p):
    c, A, a, p_, C, g, q = p
    return np.mean((c + A*N**(-a)*V**p_ + C*D**(-g)*V**q - L)**2)
forms['F4'] = (F4, 7)

# F5: L = c + A/N^a + B/V^b + C/D^g * V^p
def F5(p):
    c, A, a, B, b, C, g, p_ = p
    return np.mean((c + A*N**(-a) + B*V**(-b) + C*D**(-g)*V**p_ - L)**2)
forms['F5'] = (F5, 8)

# F6: L = c + A/N^a + B/V^b + C/D^g * N^q
def F6(p):
    c, A, a, B, b, C, g, q = p
    return np.mean((c + A*N**(-a) + B*V**(-b) + C*D**(-g)*N**q - L)**2)
forms['F6'] = (F6, 8)

# F7: Tao form with d_proxy
# F7: L = c + A/N^a + B/(V*N^k)^b + C/D^g
def F7(p):
    c, A, a, B, b, k, C, g = p
    return np.mean((c + A*N**(-a) + B*(V*N**k)**(-b) + C*D**(-g) - L)**2)
forms['F7'] = (F7, 8)

# F8: L = c + A/N^a + B/V^b + C/(D*V^p*N^q)^g
def F8(p):
    c, A, a, B, b, C, g, p_, q = p
    return np.mean((c + A*N**(-a) + B*V**(-b) + C*(D*V**p_*N**q)**(-g) - L)**2)
forms['F8'] = (F8, 9)

# F9: L = c + (A + B*V^p)/N^a + (C + D2*V^q)/D^g  (linear V in both terms)
def F9(p):
    c, A, B, p_, a, C, D2, q, g = p
    return np.mean((c + (A + B*V**p_)*N**(-a) + (C + D2*V**q)*D**(-g) - L)**2)
forms['F9'] = (F9, 9)

def smart_init(ndim, seed):
    np.random.seed(seed)
    # Initialize floor params if possible
    return np.random.randn(ndim) * 0.3

results = {}
for name, (fn, ndim) in forms.items():
    best = None
    for trial in range(100):
        np.random.seed(trial)
        init = np.random.randn(ndim) * 0.5
        # Put bias on a (alpha around 0.3)
        try:
            res = minimize(fn, init, method='Nelder-Mead', options={'maxiter':30000, 'xatol':1e-10, 'fatol':1e-10})
            if best is None or res.fun < best.fun: best = res
        except: pass
    results[name] = best
    print(f"{name}: MSE={best.fun:.6f}, params={best.x}")

